#include<bits/stdc++.h>
using namespace std;
int n;
long long ls[20001],rs[20001],dp[20001][41][41],a[20001],b[20001],c[20001];
long long dfs(int x,int cnt1,int cnt2)
{
    if(x>=n)
    {
        int temp=x-n+1;
        return c[temp]*(a[temp]+cnt1)*(b[temp]+cnt2);
    }
    if(dp[x][cnt1][cnt2]!=dp[0][0][0])
    {
        return dp[x][cnt1][cnt2];
    }
    dp[x][cnt1][cnt2]=min(dfs(ls[x],cnt1,cnt2)+dfs(rs[x],cnt1,cnt2+1),dfs(ls[x],cnt1+1,cnt2)+dfs(rs[x],cnt1,cnt2));
    return dp[x][cnt1][cnt2];
}
int main()
{
    scanf("%d",&n);
    for(int i=1;i<n;i++)
    {
        scanf("%lld%lld",&ls[i],&rs[i]);
        if(ls[i]<0)
        {
            ls[i]=n-1-ls[i];
        }
        if(rs[i]<0)
        {
            rs[i]=n-1-rs[i];
        }
    }
    for(int i=1;i<=n;i++)
    {
        scanf("%lld%lld%lld",&a[i],&b[i],&c[i]);
    }
    memset(dp,0x3f,sizeof(dp));
    printf("%lld",dfs(1,0,0));
    return 0;
}
